class Solution {
    public boolean isMatch(String s, String p) {
        // Base case: if pattern is exhausted, string must also be exhausted
        if (p.isEmpty()) return s.isEmpty();

        // Check if the very first character matches
        boolean firstMatch = (!s.isEmpty() &&
                             (p.charAt(0) == s.charAt(0) || p.charAt(0) == '.'));

        // If next char in pattern is '*', we have two choices:
        if (p.length() >= 2 && p.charAt(1) == '*') {
            // Choice 1: treat x* as empty (zero occurrences), skip x*
            // Choice 2: if first char matches, consume one from s, stay at same p
            return isMatch(s, p.substring(2)) ||
                   (firstMatch && isMatch(s.substring(1), p));
        } else {
            // No '*' ahead, must match first character and recurse on rest
            return firstMatch && isMatch(s.substring(1), p.substring(1));
        }
    }
}

class Solution {
    private Map<String, Boolean> memo = new HashMap<>();

    public boolean isMatch(String s, String p) {
        return dp(s, 0, p, 0);
    }

    private boolean dp(String s, int i, String p, int j) {
        // Build a cache key from current positions
        String key = i + "," + j;
        if (memo.containsKey(key)) return memo.get(key);

        boolean result;

        // Base case: pattern exhausted
        if (j == p.length()) {
            result = (i == s.length());
        } else {
            // First character match check
            boolean firstMatch = (i < s.length() &&
                                 (p.charAt(j) == s.charAt(i) || p.charAt(j) == '.'));

            if (j + 1 < p.length() && p.charAt(j + 1) == '*') {
                // Two branches: skip x* entirely, or consume one char if first matches
                result = dp(s, i, p, j + 2) ||
                         (firstMatch && dp(s, i + 1, p, j));
            } else {
                result = firstMatch && dp(s, i + 1, p, j + 1);
            }
        }

        memo.put(key, result);
        return result;
    }
}

import java.util.Scanner;

class Solution {
    public boolean isMatch(String s, String p) {
        int m = s.length();
        int n = p.length();

        // dp[i][j] = does s[i:] match p[j:]?
        // Size (m+1) x (n+1) to accommodate the empty-suffix base cases
        boolean[][] dp = new boolean[m + 1][n + 1];

        // Base case 1: empty string matches empty pattern
        dp[m][n] = true;

        // Base case 2: empty string s[m:] can match patterns like "a*", "a*b*", "a*b*c*"
        // Walk backwards in steps of 2; stop as soon as we hit a non-'x*' pair
        for (int j = n - 2; j >= 0; j -= 2) {
            if (p.charAt(j + 1) == '*') {
                dp[m][j] = true;  // x* counts as zero occurrences → matches empty s
            } else {
                break;            // no further j can salvage an empty-s match
            }
        }

        // Fill remaining cells bottom-up (i from m-1 to 0, j from n-1 to 0)
        // dp[i][j] depends on dp[i+1][...] and dp[i][j+2], so fill row by row downward
        for (int i = m - 1; i >= 0; i--) {
            for (int j = n - 1; j >= 0; j--) {

                // Does the current pattern character match the current string character?
                // '.' is a wildcard that matches any single character
                boolean firstMatch = (p.charAt(j) == s.charAt(i) || p.charAt(j) == '.');

                if (j + 1 < n && p.charAt(j + 1) == '*') {
                    // Pattern has 'x*' starting at j — two choices:
                    // Option A: use x* as ZERO occurrences → skip both j and j+1 in pattern
                    // Option B: use x* as ONE occurrence  → consume s[i] (if it matches) and stay at j
                    //           (staying at j lets x* match more chars in future iterations)
                    dp[i][j] = dp[i][j + 2]                  // Option A: skip x*
                             || (firstMatch && dp[i + 1][j]); // Option B: consume one, stay
                } else {
                    // No '*' following — straightforward: both chars must match, advance both
                    dp[i][j] = firstMatch && dp[i + 1][j + 1];
                }
            }
        }

        // dp[0][0]: does the full string s[0:] match the full pattern p[0:]?
        return dp[0][0];
    }

    // -----------------------------------------------------------------------
    // Main — drives a few representative test cases and prints pass/fail
    // -----------------------------------------------------------------------
    public static void main(String[] args) {
        Solution sol = new Solution();

        // Each entry: { s, p, expectedResult }
        String[][] tests = {
            // Provided example
            {"aab",   "c*a*b",  "true"},

            // Classic '.*' wildcard — matches everything
            {"mississippi", ".*",     "true"},

            // '.*' matches empty string too
            {"",      ".*",     "true"},

            // Simple dot — must match exactly one char
            {"a",     ".",      "true"},
            {"ab",    ".",      "false"},

            // '*' used as zero occurrences
            {"b",     "a*b",    "true"},
            {"",      "a*",     "true"},

            // No match
            {"aa",    "a",      "false"},
            {"aaa",   "ab*a",   "false"},

            // Chained 'x*' patterns against empty string
            {"",      "a*b*c*", "true"},

            // Dot-star followed by literal
            {"abcdef", ".*f",   "true"},
            {"abcdef", ".*e",   "false"},

            // Pattern longer than string
            {"a",     "ab*",    "true"},  // b* = zero b's
            {"a",     "ab*c*",  "true"},  // b*c* = zero of each
        };

        int passed = 0;
        System.out.println("Running " + tests.length + " test cases...\n");

        for (String[] test : tests) {
            String s        = test[0];
            String p        = test[1];
            boolean expected = Boolean.parseBoolean(test[2]);
            boolean actual   = sol.isMatch(s, p);
            boolean ok       = (actual == expected);
            if (ok) passed++;

            System.out.printf("%s  s=\"%-12s\"  p=\"%-10s\"  expected=%-5s  got=%-5s%n",
                ok ? "PASS" : "FAIL",
                s, p,
                expected, actual);
        }

        System.out.println("\n" + passed + "/" + tests.length + " tests passed.");

        // Interactive mode: read s and p from stdin if extra args supplied
        if (args.length == 2) {
            String s = args[0];
            String p = args[1];
            System.out.println("\nCustom input: s=\"" + s + "\"  p=\"" + p + "\"");
            System.out.println("Result: " + sol.isMatch(s, p));
        }
    }
}

