Yes. Since dp[i][j] only ever looks at the current row (dp[i][j+2]) and the row directly below (dp[i+1][j] and dp[i+1][j+1]), we only need to keep two rows alive at a time — current and next. We can use two 1D arrays of size n+1, swapping them as we go from i=m down to i=0. That brings space to O(n). Here's the modified solution:

import java.util.Scanner;

class Solution {
    public boolean isMatch(String s, String p) {
        int m = s.length();
        int n = p.length();

        // 'next' represents dp[i+1][...], i.e. the row below the current one
        boolean[] next = new boolean[n + 1];

        // Base case: empty s matches empty p
        next[n] = true;

        // Base case: empty s against trailing 'x*' sequences
        for (int j = n - 2; j >= 0; j -= 2) {
            if (p.charAt(j + 1) == '*') next[j] = true;
            else break;
        }

        // Fill from i = m-1 up to i = 0
        for (int i = m - 1; i >= 0; i--) {
            boolean[] curr = new boolean[n + 1];
            // curr[n] stays false: s[i:] is non-empty, pattern empty = no match
            for (int j = n - 1; j >= 0; j--) {
                boolean firstMatch = (p.charAt(j) == s.charAt(i) || p.charAt(j) == '.');
                if (j + 1 < n && p.charAt(j + 1) == '*') {
                    curr[j] = curr[j + 2] || (firstMatch && next[j]);
                } else {
                    curr[j] = firstMatch && next[j + 1];
                }
            }
            next = curr;
        }

        return next[0];
    }

    public static void main(String[] args) {
        Solution sol = new Solution();
        System.out.println(sol.isMatch("aab",   "c*a*b"));  // true
        System.out.println(sol.isMatch("aa",    "a"));       // false
        System.out.println(sol.isMatch("",       "a*b*"));   // true
        System.out.println(sol.isMatch("abcdef", ".*f"));    // true
    }
}
